t.script:
(function() {
    var rpc = window.dpJsonRpc || function(route, params) {
        return new Promise(function(resolve, reject) {
            var xhr = new XMLHttpRequest();
            xhr.open('POST', route, true);
            xhr.withCredentials = true;
            xhr.setRequestHeader('Content-Type', 'application/json');
            xhr.setRequestHeader('X-Requested-With', 'XMLHttpRequest');
            xhr.onload = function() {
                try { var d = JSON.parse(xhr.responseText); resolve(d.result); }
                catch(e) { reject(e); }
            };
            xhr.onerror = function() { reject(new Error('Network error')); };
            xhr.send(JSON.stringify({jsonrpc:'2.0',method:'call',id:1,params:params||{}}));
        });
    };
    function init() {
        var all = document.getElementById('dp-receive-all');
        if (all) {
            all.addEventListener('click', function() {
                var btns = document.querySelectorAll('.dp-btn-receive');
                if (!btns.length) { alert('No pending orders'); return; }
                all.disabled = true; all.textContent = 'Processing…';
                Promise.all(Array.from(btns).map(function(b) {
                    return rpc('/delivery-portal/receive-order', {
                        order_id: parseInt(b.dataset.orderId),
                        line_id: parseInt(b.dataset.lineId) || 0
                    });
                })).then(function() { window.location.reload(); })
                .catch(function(e) { alert('Error: '+e.message); all.disabled=false; all.textContent='✅ Receive All'; });
            });
        }
        document.querySelectorAll('.dp-btn-receive').forEach(function(b) {
            b.addEventListener('click', function() {
                b.disabled = true;
                rpc('/delivery-portal/receive-order', {order_id: parseInt(b.dataset.orderId), line_id: parseInt(b.dataset.lineId)||0})
                .then(function() { window.location.reload(); })
                .catch(function(e) { alert('Error: '+e.message); b.disabled=false; });
            });
        });
        document.querySelectorAll('.dp-btn-no-receive').forEach(function(b) {
            b.addEventListener('click', function() {
                if (!confirm('Mark as not received?')) return;
                b.disabled = true;
                rpc('/delivery-portal/no-receive-order', {order_id: parseInt(b.dataset.orderId), line_id: parseInt(b.dataset.lineId)||0})
                .then(function() { window.location.reload(); })
                .catch(function(e) { alert('Error: '+e.message); b.disabled=false; });
            });
        });
    }
    if (document.readyState === 'loading') { document.addEventListener('DOMContentLoaded', init); } else { init(); }

    // ── SCAN & RECEIVE ──────────────────────────────────────
    function initScan() {
        var scanBtn = document.getElementById('dp-scan-receive-btn');
        var dialog  = document.getElementById('dp-scan-dialog');
        var closeBtn= document.getElementById('dp-scan-close');
        var input   = document.getElementById('dp-scan-input');
        var addBtn  = document.getElementById('dp-scan-confirm');
        var list    = document.getElementById('dp-scanned-list');
        var emptyMsg= document.getElementById('dp-scan-empty');
        var recvBtn = document.getElementById('dp-scan-receive-confirm');
        var msgEl   = document.getElementById('dp-scan-msg');
        var scanned = {}; // {orderName: {order_id, line_id}}

        // Build lookup from page orders
        var orderMap = {};
        document.querySelectorAll('.dp-btn-receive').forEach(function(b) {
            var name = b.dataset.orderName;
            if (name) orderMap[name.toUpperCase()] = {
                order_id: parseInt(b.dataset.orderId),
                line_id:  parseInt(b.dataset.lineId) || 0
            };
        });

        if (!scanBtn) return;

        scanBtn.addEventListener('click', function() {
            dialog.style.display = 'flex';
            setTimeout(function(){ input.focus(); }, 100);
        });

        closeBtn.addEventListener('click', function() {
            dialog.style.display = 'none';
            input.value = '';
        });

        function addOrder() {
            var val = input.value.trim().toUpperCase();
            if (!val) return;
            input.value = '';
            input.focus();

            if (scanned[val]) {
                msgEl.style.color = '#f59e0b';
                msgEl.textContent = val + ' already added';
                return;
            }
            if (!orderMap[val]) {
                msgEl.style.color = '#ef4444';
                msgEl.textContent = '❌ ' + val + ' not found in this trip';
                return;
            }
            scanned[val] = orderMap[val];
            emptyMsg.style.display = 'none';
            msgEl.textContent = '';

            var item = document.createElement('div');
            item.style.cssText = 'display:flex;justify-content:space-between;align-items:center;padding:8px 10px;background:#f0fdf4;border-radius:6px;margin-bottom:6px;';
            item.innerHTML = '✓ ' + val + '' +
                '✕';
            item.querySelector('button').addEventListener('click', function() {
                delete scanned[this.dataset.order];
                item.remove();
                if (!Object.keys(scanned).length) emptyMsg.style.display = 'block';
            });
            list.appendChild(item);
        }

        addBtn.addEventListener('click', addOrder);
        input.addEventListener('keydown', function(e) {
            if (e.key === 'Enter') { e.preventDefault(); addOrder(); }
        });

        recvBtn.addEventListener('click', function() {
            var keys = Object.keys(scanned);
            if (!keys.length) { msgEl.style.color='#ef4444'; msgEl.textContent='No orders scanned'; return; }
            recvBtn.disabled = true;
            recvBtn.textContent = 'Processing…';
            Promise.all(keys.map(function(k) {
                return rpc('/delivery-portal/receive-order', scanned[k]);
            })).then(function() {
                window.location.reload();
            }).catch(function(e) {
                recvBtn.disabled = false;
                recvBtn.textContent = '✅ Confirm Reception';
                msgEl.style.color = '#ef4444';
                msgEl.textContent = 'Error: ' + e.message;
            });
        });
    }
    if (document.readyState === 'loading') { document.addEventListener('DOMContentLoaded', initScan); } else { initScan(); }
})();

