(function() {
    function rpc(route, params) {
        return new Promise(function(resolve, reject) {
            var xhr = new XMLHttpRequest();
            xhr.open("POST", route, true);
            xhr.withCredentials = true;
            xhr.setRequestHeader("Content-Type", "application/json");
            xhr.setRequestHeader("X-Requested-With", "XMLHttpRequest");
            xhr.onload = function() {
                try { var d = JSON.parse(xhr.responseText); resolve(d.result); }
                catch(e) { reject(e); }
            };
            xhr.onerror = function() { reject(new Error("Network error")); };
            xhr.send(JSON.stringify({jsonrpc:"2.0",method:"call",id:1,params:params||{}}));
        });
    }

    function setup() {
        var btn = document.getElementById("dp-submit-remittance");
        if (!btn) return;

        var selAll     = document.getElementById("dp-select-all");
        var totEl      = document.getElementById("dp-selected-total");
        var cntEl      = document.getElementById("dp-selected-count");
        var sumCash    = document.getElementById("dp-sum-cash");
        var sumCarrier = document.getElementById("dp-sum-carrier");
        var sumNet     = document.getElementById("dp-sum-net");

        function getChecked() {
            return [].slice.call(document.querySelectorAll(".dp-order-check:checked"));
        }

        function update() {
            var checked      = getChecked();
            var cashTotal    = 0;
            var carrierTotal = 0;
            checked.forEach(function(x) {
                cashTotal    += parseFloat(x.getAttribute("data-amount")       || 0);
                carrierTotal += parseFloat(x.getAttribute("data-carrier-cost") || 0);
            });
            var net = cashTotal - carrierTotal;
            if (totEl)      totEl.textContent     = "KD " + cashTotal.toFixed(3);
            if (cntEl)      cntEl.textContent     = checked.length + " orders";
            if (sumCash)    sumCash.textContent    = "KD " + cashTotal.toFixed(3);
            if (sumCarrier) sumCarrier.textContent = "KD " + carrierTotal.toFixed(3);
            if (sumNet)     sumNet.textContent     = "KD " + net.toFixed(3);
            btn.disabled       = checked.length === 0;
            btn.style.opacity  = checked.length ? "1" : "0.5";
        }

        // Check all on init + attach listeners
        var allCbs = document.querySelectorAll(".dp-order-check");
        allCbs.forEach(function(cb) {
            cb.checked = true;
            cb.addEventListener("change", function() {
                var all = document.querySelectorAll(".dp-order-check");
                var chk = getChecked();
                if (selAll) {
                    selAll.checked       = chk.length === all.length;
                    selAll.indeterminate = chk.length > 0 && chk.length < all.length;
                }
                update();
            });
        });

        if (selAll) {
            selAll.checked = true;
            selAll.addEventListener("change", function() {
                document.querySelectorAll(".dp-order-check").forEach(function(cb){ cb.checked = selAll.checked; });
                update();
            });
        }

        update();

        btn.addEventListener("click", function() {
            var ids = getChecked().map(function(c){ return parseInt(c.dataset.orderId); }).filter(Boolean);
            if (!ids.length) { alert("Select at least one order"); return; }
            var ref = (document.getElementById("dp-carrier-ref")||{}).value || "";
            btn.disabled = true;
            btn.textContent = "Sending...";
            rpc("/delivery-portal/remittance/submit", {order_ids: ids, carrier_ref: ref})
            .then(function(r) {
                if (r && r.success) {
                    window.location.href = "/delivery-portal/remittance/" + r.remittance_id;
                } else {
                    alert((r && r.error) || "Error occurred");
                    btn.disabled = false; btn.textContent = "Send to Uellow ←";
                }
            }).catch(function(e) {
                alert("Error: " + e.message);
                btn.disabled = false; btn.textContent = "Send to Uellow ←";
            });
        });
    }

    if (document.readyState === "loading") { document.addEventListener("DOMContentLoaded", setup); }
    else { setup(); }
})();
